local function valid(b,r,c,ch) for i=1,9 do if b[r][i]==ch or b[i][c]==ch then return false end end local br=math.floor((r-1)/3)*3+1 local bc=math.floor((c-1)/3)*3+1 for i=br,br+2 do for j=bc,bc+2 do if b[i][j]==ch then return false end end end return true end
local function solve(b) for r=1,9 do for c=1,9 do if b[r][c]=='.' then for ch=49,57 do local s=string.char(ch); if valid(b,r,c,s) then b[r][c]=s; if solve(b) then return true end; b[r][c]='.' end end return false end end end return true end
local lines={} for line in io.lines() do table.insert(lines,line) end if #lines==0 or lines[1]:match('^%s*$') then os.exit() end local idx,t=2,tonumber(lines[1]); local out={} for _=1,t do local b={} for i=1,9 do b[i]={}; local row=lines[idx]; idx=idx+1; for j=1,9 do b[i][j]=row:sub(j,j) end end solve(b); for i=1,9 do out[#out+1]=table.concat(b[i]) end end io.write(table.concat(out,'\n'))
